import { useState } from "react";
import { Month } from "./Months";

interface YearProps {
    year: string;
}

export const Year: React.FC<YearProps> = ({ year }) => {
    const [extend, setExtend] = useState(false);

    const toggleExtend = () => {
        setExtend(!extend);
    };


    return (
        <div className="year">
            <span className="year-title" onClick={toggleExtend}>{year}</span>
            {extend && <Month month="October" />}
        </div>

    );
};
